import { NextResponse } from 'next/server'
import { generateTextWithMeta } from '@/lib/gemini'
import { getAuthenticatedUser, unauthorizedResponse } from '@/lib/api-utils'
import { checkRateLimit, rateLimitExceededResponse, rateLimitHeaders, RATE_LIMITS } from '@/lib/rate-limit'
import { createClient } from '@/lib/supabase/server'
import { addMinutes, addHours, addDays } from 'date-fns'

interface ChatAction {
    type: 'reminder' | 'note'
    success: boolean
    message: string
    data?: Record<string, unknown>
}

// Parse time expressions like "in 30 minutes", "tomorrow", "in 2 hours"
function parseTimeExpression(text: string): Date | null {
    const now = new Date()
    const lowerText = text.toLowerCase()

    // "in X minutes"
    const minutesMatch = lowerText.match(/in (\d+) minutes?/i)
    if (minutesMatch) {
        return addMinutes(now, parseInt(minutesMatch[1]))
    }

    // "in X hours"
    const hoursMatch = lowerText.match(/in (\d+) hours?/i)
    if (hoursMatch) {
        return addHours(now, parseInt(hoursMatch[1]))
    }

    // "tomorrow"
    if (lowerText.includes('tomorrow')) {
        const tomorrow = addDays(now, 1)
        tomorrow.setHours(9, 0, 0, 0) // Default to 9 AM
        return tomorrow
    }

    // "in X days"
    const daysMatch = lowerText.match(/in (\d+) days?/i)
    if (daysMatch) {
        return addDays(now, parseInt(daysMatch[1]))
    }

    // Default: 15 minutes from now
    return addMinutes(now, 15)
}

// Detect if message contains an action command
function detectAction(message: string): { type: 'reminder' | 'note' | null; content: string } {
    const lowerMsg = message.toLowerCase()

    // Reminder patterns
    const reminderPatterns = [
        /remind me (?:to |about )?(.+)/i,
        /set a reminder (?:to |for |about )?(.+)/i,
        /add reminder (?:to |for |about )?(.+)/i,
        /create reminder (?:to |for |about )?(.+)/i,
    ]

    for (const pattern of reminderPatterns) {
        const match = message.match(pattern)
        if (match) {
            return { type: 'reminder', content: match[1].trim() }
        }
    }

    // Note patterns
    const notePatterns = [
        /(?:create|add|make|write) (?:a )?note (?:about |for |titled )?(.+)/i,
        /note (?:down|this)[ :]+(.+)/i,
        /save (?:this )?(?:as )?(?:a )?note[ :]+(.+)/i,
    ]

    for (const pattern of notePatterns) {
        const match = message.match(pattern)
        if (match) {
            return { type: 'note', content: match[1].trim() }
        }
    }

    return { type: null, content: '' }
}

export async function POST(request: Request) {
    try {
        // Check authentication
        const user = await getAuthenticatedUser()
        if (!user) {
            return unauthorizedResponse()
        }

        // Check rate limit (20 chat messages per minute)
        const rl = await checkRateLimit(
            user.id,
            RATE_LIMITS.chat.endpoint,
            RATE_LIMITS.chat.limit,
            RATE_LIMITS.chat.windowSeconds
        )
        if (!rl.allowed) {
            return rateLimitExceededResponse({
                limit: RATE_LIMITS.chat.limit,
                remaining: rl.remaining,
                resetAt: rl.resetAt,
            })
        }

        const { messages } = await request.json()

        if (!messages || !Array.isArray(messages)) {
            return NextResponse.json(
                { error: 'Messages array is required' },
                { status: 400 }
            )
        }

        // Get the latest user message
        const latestMessage = messages[messages.length - 1]
        const userMessage = latestMessage?.role === 'user' ? latestMessage.content : ''

        // Detect if this is an action command
        const actionDetected = detectAction(userMessage)
        let action: ChatAction | null = null

        if (actionDetected.type) {
            const supabase = await createClient()

            if (actionDetected.type === 'reminder') {
                // Create reminder
                const reminderTime = parseTimeExpression(userMessage)
                const reminderTitle = actionDetected.content
                    .replace(/in \d+ (minutes?|hours?|days?)/gi, '')
                    .replace(/tomorrow/gi, '')
                    .trim()

                // Note: Reminders are stored in localStorage on client side
                // So we'll return the action for the frontend to handle
                action = {
                    type: 'reminder',
                    success: true,
                    message: `I've created a reminder for you! "${reminderTitle}" scheduled for ${reminderTime?.toLocaleString() || 'soon'}.`,
                    data: {
                        title: reminderTitle || actionDetected.content,
                        datetime: reminderTime?.toISOString(),
                    }
                }
            } else if (actionDetected.type === 'note') {
                // Create note in database
                const noteTitle = actionDetected.content.slice(0, 100)
                const { data, error } = await supabase
                    .from('notes')
                    .insert({
                        user_id: user.id,
                        title: noteTitle,
                        content: `<p>${actionDetected.content}</p>`,
                        is_pinned: false,
                    })
                    .select('id')
                    .single()

                if (error) {
                    action = {
                        type: 'note',
                        success: false,
                        message: 'Sorry, I couldn\'t create the note. Please try again.'
                    }
                } else {
                    action = {
                        type: 'note',
                        success: true,
                        message: `Done! I've created a new note titled "${noteTitle}". You can find it in your Notes section.`,
                        data: { id: data?.id, title: noteTitle }
                    }
                }
            }

            // Return action result directly without calling AI
            if (action) {
                return NextResponse.json(
                    { response: action.message, action },
                    {
                        headers: {
                            ...rateLimitHeaders({
                                limit: RATE_LIMITS.chat.limit,
                                remaining: rl.remaining,
                                resetAt: rl.resetAt,
                            })
                        }
                    }
                )
            }
        }

        // Regular chat - not an action
        // Limit conversation history to prevent token abuse
        const recentMessages = messages.slice(-10)

        // Build conversation context
        const conversationHistory = recentMessages
            .map((msg: { role: string; content: string }) =>
                `${msg.role === 'user' ? 'Student' : 'Tutor'}: ${msg.content}`
            )
            .join('\n')

        const prompt = `You are a helpful, friendly study tutor called "Study Buddy" for the StudentHub platform.

Role & Restrictions:
1. STRICTLY limited to academic topics, study advice, and helping users navigate this StudentHub website.
2. Refuse to answer inappropriate, NSFW, political, or non-educational off-topic questions.
3. If asked about website features, explain them: Dashboard, Notes (AI-powered), Tasks, Pomodoro, Flashcards, Grades (CGPA), and Budget.

Special Commands (tell users about these!):
- "Remind me to..." - Creates a reminder
- "Create a note about..." - Creates a new note
- "Add reminder for..." - Creates a reminder

Guidelines:
- Be encouraging and supportive
- Explain concepts in simple, easy-to-understand terms
- Use examples when helpful
- Keep responses concise but thorough
- If you don't know something, be honest about it
- Focus on education and learning

Conversation so far:
${conversationHistory}

Provide a helpful response as the tutor. Be conversational and friendly.`

        const supabaseChat = await createClient()
        const conversationId = crypto.randomUUID()

        // Save user message
        await supabaseChat
            .from('chat_messages')
            .insert({
                user_id: user.id,
                role: 'user',
                content: userMessage,
                conversation_id: conversationId,
            })

        // Generate AI response with metadata
        const result = await generateTextWithMeta(prompt)

        // Save assistant message with token count
        await supabaseChat
            .from('chat_messages')
            .insert({
                user_id: user.id,
                role: 'assistant',
                content: result.text,
                conversation_id: conversationId,
                model: result.model,
                tokens_used: result.tokensUsed,
            })

        return NextResponse.json(
            { response: result.text },
            {
                headers: {
                    ...rateLimitHeaders({
                        limit: RATE_LIMITS.chat.limit,
                        remaining: rl.remaining,
                        resetAt: rl.resetAt,
                    })
                }
            }
        )
    } catch (error) {
        console.error('Chat API Error:', error)
        return NextResponse.json(
            { error: 'Failed to generate response. Please try again.' },
            { status: 500 }
        )
    }
}

import { NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'
import { generateText } from '@/lib/gemini'
import { Part } from '@google/generative-ai'
import { checkRateLimit, rateLimitExceededResponse, rateLimitHeaders, RATE_LIMITS } from '@/lib/rate-limit'

function normalizeStoragePath(path: string): string {
    const trimmed = (path || '').trim()
    if (!trimmed) return trimmed
    if (/^https?:\/\//i.test(trimmed)) {
        try {
            const url = new URL(trimmed)
            const pathname = url.pathname || ''
            const bucketMarker = '/storage/v1/object/public/' // Adjust based on your public access
            // For private/authenticated buckets, download logic handles usually paths/keys.
            // Assuming we store relative path in DB from previous code: "user_id/subject_id/filename"
            return trimmed // simplified for now, usually we expect the DB to store the KEY
        } catch { return trimmed }
    }
    return trimmed
}

export async function POST(request: Request) {
    try {
        const supabase = await createClient()
        const { data: { user } } = await supabase.auth.getUser()

        if (!user) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
        }

        const rl = await checkRateLimit(
            user.id,
            RATE_LIMITS.exam_prep.endpoint,
            RATE_LIMITS.exam_prep.limit,
            RATE_LIMITS.exam_prep.windowSeconds
        )
        if (!rl.allowed) {
            return rateLimitExceededResponse({
                limit: RATE_LIMITS.exam_prep.limit,
                remaining: rl.remaining,
                resetAt: rl.resetAt,
            })
        }

        const body = await request.json()
        const { subjectId, syllabusPath } = body

        if (!subjectId || !syllabusPath) {
            return NextResponse.json({ error: 'Missing required fields' }, { status: 400 })
        }

        // Download Syllabus
        const validPath = normalizeStoragePath(syllabusPath)
        const { data: fileData, error: downloadError } = await supabase.storage
            .from('exam-pdfs')
            .download(validPath)

        if (downloadError || !fileData) {
            console.error('Syllabus download error:', downloadError)
            return NextResponse.json({ error: 'Failed to download syllabus' }, { status: 500 })
        }

        const buffer = await fileData.arrayBuffer()
        const base64 = Buffer.from(buffer).toString('base64')
        const ext = validPath.split('.').pop()?.toLowerCase()
        let mimeType = 'application/pdf'
        if (ext === 'png') mimeType = 'image/png'
        if (ext === 'jpg' || ext === 'jpeg') mimeType = 'image/jpeg'

        // Construct AI Prompt
        const parts: (string | Part)[] = []
        parts.push({
            text: `Analyze this syllabus document. 
            Identify and EXTRACT any text that is visually HIGHLIGHTED (yellow/marker), CIRCLED (red pen), or explicitly marked as "Important".
            
            If NO text is clearly highlighted/marked, then summarize the top 3-5 high-level core topics listed in the document.

            Output Format:
            - Return ONLY the extracted text/topics. 
            - Use bullet points.
            - Be specific.`
        })
        parts.push({
            inlineData: {
                data: base64,
                mimeType
            }
        })

        const extractedText = await generateText(parts)

        // Update Database
        const { error: updateError } = await supabase
            .from('exam_subjects')
            .update({ important_questions: extractedText })
            .eq('id', subjectId)
            .eq('user_id', user.id)

        if (updateError) {
            throw updateError
        }

        return NextResponse.json(
            { success: true, important_topics: extractedText },
            {
                headers: {
                    ...rateLimitHeaders({
                        limit: RATE_LIMITS.exam_prep.limit,
                        remaining: rl.remaining,
                        resetAt: rl.resetAt,
                    }),
                },
            }
        )

    } catch (error) {
        console.error('Syllabus analysis error:', error)
        return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 })
    }
}

'use client'

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from '@/components/ui/dialog'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select'
import {
    Sheet,
    SheetContent,
    SheetTrigger,
} from '@/components/ui/sheet'
import {
    ClipboardList,
    Plus,
    Calendar,
    CheckCircle2,
    Clock,
    Loader2,
    Trash2,
    Users,
    FileText,
    AlertCircle,
    MessageCircle,
    UserPlus,
    RefreshCw
} from 'lucide-react'
import {
    AlertDialog,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from '@/components/ui/alert-dialog'
import { cn } from '@/lib/utils'
import { toast } from 'sonner'
import { format, isPast, isToday } from 'date-fns'
import { InviteToGroupDialog } from '@/components/assignments/InviteToGroupDialog'
import { PendingInvitations } from '@/components/assignments/PendingInvitations'
import { GroupChat } from '@/components/assignments/GroupChat'

// Google icon component
function GoogleIcon({ className }: { className?: string }) {
    return (
        <svg className={className} viewBox="0 0 24 24" fill="currentColor">
            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
            <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
        </svg>
    )
}

interface Assignment {
    id: string
    title: string
    course: string | null
    due_date: string | null
    status: 'assigned' | 'missing' | 'done'
    grade: string | null
    is_group: boolean
    group_id: string | null
    notes: string | null
    created_at: string
}

const statusConfig = {
    'assigned': { label: 'Assigned', color: 'bg-blue-500/10 text-blue-500 border-blue-500/30', icon: Clock },
    'missing': { label: 'Missing', color: 'bg-red-500/10 text-red-500 border-red-500/30', icon: AlertCircle },
    'done': { label: 'Done', color: 'bg-emerald-500/10 text-emerald-500 border-emerald-500/30', icon: CheckCircle2 }
}

export default function AssignmentsPage() {
    const [assignments, setAssignments] = useState<Assignment[]>([])
    const [loading, setLoading] = useState(true)
    const [dialogOpen, setDialogOpen] = useState(false)
    const [creating, setCreating] = useState(false)
    const [importing, setImporting] = useState(false)
    const [filter, setFilter] = useState<string>('assigned')
    const [resyncing, setResyncing] = useState(false)
    const [googleAlert, setGoogleAlert] = useState<{ open: boolean; message: string }>({ open: false, message: '' })
    const [newAssignment, setNewAssignment] = useState({
        title: '',
        course: '',
        due_date: '',
        is_group: false,
        notes: ''
    })
    const supabase = createClient()

    const resyncStatus = async () => {
        setResyncing(true)
        try {
            const res = await fetch('/api/google/classroom/resync', { method: 'POST' })
            const data = await res.json()
            if (res.ok) {
                toast.success(data.message || `Updated ${data.updated} assignments`)
                fetchAssignments()
            } else if (data.needsReconnect) {
                setGoogleAlert({ open: true, message: data.error })
            } else {
                toast.error(data.error || 'Failed to resync')
            }
        } catch {
            toast.error('Failed to resync assignments')
        } finally {
            setResyncing(false)
        }
    }

    useEffect(() => {
        fetchAssignments()
    }, [])

    const fetchAssignments = async () => {
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) return

            const { data, error } = await supabase
                .from('assignments')
                .select('*')
                .eq('user_id', user.id)
                .order('due_date', { ascending: true, nullsFirst: false })

            if (error) throw error

            // Map old status values to new ones and check for overdue
            const mapStatus = (oldStatus: string, dueDate: string | null): 'assigned' | 'missing' | 'done' => {
                let status: 'assigned' | 'missing' | 'done'
                switch (oldStatus) {
                    case 'pending':
                    case 'in-progress':
                        status = 'assigned'
                        break
                    case 'submitted':
                    case 'graded':
                        status = 'done'
                        break
                    case 'assigned':
                    case 'missing':
                    case 'done':
                        status = oldStatus as 'assigned' | 'missing' | 'done'
                        break
                    default:
                        status = 'assigned'
                }

                // If assigned and past due date, mark as missing
                if (status === 'assigned' && dueDate && isPast(new Date(dueDate))) {
                    status = 'missing'
                }

                return status
            }

            const mappedData = (data || []).map(a => ({
                ...a,
                status: mapStatus(a.status, a.due_date)
            }))

            setAssignments(mappedData)
        } catch (error) {
            console.error('Error fetching assignments:', error)
        } finally {
            setLoading(false)
        }
    }

    const createAssignment = async () => {
        if (!newAssignment.title.trim()) {
            toast.error('Please enter an assignment title')
            return
        }

        setCreating(true)
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error('Not authenticated')

            const { error } = await supabase
                .from('assignments')
                .insert({
                    user_id: user.id,
                    title: newAssignment.title.trim(),
                    course: newAssignment.course || null,
                    due_date: newAssignment.due_date || null,
                    is_group: newAssignment.is_group,
                    notes: newAssignment.notes || null,
                    status: 'assigned'
                })

            if (error) throw error

            toast.success('Assignment added!')
            setDialogOpen(false)
            setNewAssignment({ title: '', course: '', due_date: '', is_group: false, notes: '' })
            fetchAssignments()
        } catch (error: unknown) {
            const errorMessage = error instanceof Error ? error.message :
                (error && typeof error === 'object' && 'message' in error) ? String((error as { message: string }).message) :
                    JSON.stringify(error)
            console.error('Error creating assignment:', errorMessage, error)
            toast.error(`Failed to create assignment: ${errorMessage}`)
        } finally {
            setCreating(false)
        }
    }

    const updateStatus = async (id: string, status: Assignment['status']) => {
        try {
            const { error } = await supabase
                .from('assignments')
                .update({ status })
                .eq('id', id)

            if (error) throw error
            fetchAssignments()
        } catch (error) {
            console.error('Error updating assignment:', error)
        }
    }

    const deleteAssignment = async (id: string) => {
        try {
            const { error } = await supabase
                .from('assignments')
                .delete()
                .eq('id', id)

            if (error) throw error
            toast.success('Assignment deleted')
            fetchAssignments()
        } catch (error) {
            console.error('Error deleting assignment:', error)
        }
    }

    const importFromClassroom = async () => {
        setImporting(true)
        try {
            const res = await fetch('/api/google/classroom', { method: 'POST' })
            const data = await res.json()

            if (!res.ok) {
                if (data.needsReconnect || data.error === 'No Google account connected for Classroom' || data.error === 'Google not connected') {
                    setGoogleAlert({
                        open: true,
                        message: data.error || 'Please connect your Google account to import assignments from Classroom.',
                    })
                } else {
                    toast.error(data.error || 'Failed to import')
                }
                return
            }

            toast.success(data.message || `Imported ${data.imported} assignments`)
            fetchAssignments()
        } catch {
            toast.error('Failed to import from Google Classroom')
        } finally {
            setImporting(false)
        }
    }

    const filteredAssignments = assignments.filter((a: Assignment) => {
        if (filter === 'all') return true
        return a.status === filter
    })

    const stats = {
        total: assignments.length,
        assigned: assignments.filter(a => a.status === 'assigned').length,
        done: assignments.filter(a => a.status === 'done').length,
        missing: assignments.filter(a => a.status === 'missing').length
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center h-[50vh]">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    return (
        <div className="space-y-8">
            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold gradient-text">Assignments</h1>
                    <p className="text-muted-foreground mt-1">Track your assignments and deadlines</p>
                </div>

                <div className="flex gap-2 flex-wrap">
                    <Button
                        variant="outline"
                        onClick={resyncStatus}
                        disabled={resyncing}
                        className="gap-2"
                        title="Update status for all assignments from Google Classroom"
                    >
                        {resyncing ? (
                            <Loader2 className="h-4 w-4 animate-spin" />
                        ) : (
                            <RefreshCw className="h-4 w-4" />
                        )}
                        <span className="hidden sm:inline">Resync Status</span>
                    </Button>
                    <Button
                        variant="outline"
                        onClick={importFromClassroom}
                        disabled={importing}
                        className="gap-2"
                    >
                        {importing ? (
                            <Loader2 className="h-4 w-4 animate-spin" />
                        ) : (
                            <GoogleIcon className="h-4 w-4" />
                        )}
                        Import from Classroom
                    </Button>
                    <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
                        <DialogTrigger asChild>
                            <Button className="gradient-primary text-white gap-2">
                                <Plus className="h-4 w-4" />
                                Add Assignment
                            </Button>
                        </DialogTrigger>
                        <DialogContent className="sm:max-w-md">
                            <DialogHeader>
                                <DialogTitle>New Assignment</DialogTitle>
                                <DialogDescription>Add a new assignment to track</DialogDescription>
                            </DialogHeader>

                            <div className="space-y-4 py-4">
                                <div className="space-y-2">
                                    <Label htmlFor="title">Assignment Title</Label>
                                    <Input
                                        id="title"
                                        placeholder="e.g. Data Structures Lab 3"
                                        value={newAssignment.title}
                                        onChange={(e) => setNewAssignment({ ...newAssignment, title: e.target.value })}
                                    />
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="course">Course</Label>
                                        <Input
                                            id="course"
                                            placeholder="e.g. CSE2001"
                                            value={newAssignment.course}
                                            onChange={(e) => setNewAssignment({ ...newAssignment, course: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="due_date">Due Date</Label>
                                        <Input
                                            id="due_date"
                                            type="datetime-local"
                                            value={newAssignment.due_date}
                                            onChange={(e) => setNewAssignment({ ...newAssignment, due_date: e.target.value })}
                                        />
                                    </div>
                                </div>

                                <div className="flex items-center gap-2">
                                    <input
                                        type="checkbox"
                                        id="is_group"
                                        checked={newAssignment.is_group}
                                        onChange={(e) => setNewAssignment({ ...newAssignment, is_group: e.target.checked })}
                                        className="rounded"
                                    />
                                    <Label htmlFor="is_group" className="cursor-pointer">Group Assignment</Label>
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="notes">Notes (Optional)</Label>
                                    <Textarea
                                        id="notes"
                                        placeholder="Any additional notes..."
                                        value={newAssignment.notes}
                                        onChange={(e) => setNewAssignment({ ...newAssignment, notes: e.target.value })}
                                        rows={2}
                                    />
                                </div>
                            </div>

                            <DialogFooter>
                                <Button variant="outline" onClick={() => setDialogOpen(false)}>Cancel</Button>
                                <Button onClick={createAssignment} disabled={creating} className="gradient-primary text-white">
                                    {creating ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
                                    Add Assignment
                                </Button>
                            </DialogFooter>
                        </DialogContent>
                    </Dialog>
                </div>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <Card className="glass-card">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-indigo-500/10">
                                <ClipboardList className="h-5 w-5 text-indigo-400" />
                            </div>
                            <div>
                                <p className="text-2xl font-bold">{stats.total}</p>
                                <p className="text-xs text-muted-foreground">Total</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                <Card className="glass-card">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-blue-500/10">
                                <Clock className="h-5 w-5 text-blue-400" />
                            </div>
                            <div>
                                <p className="text-2xl font-bold">{stats.assigned}</p>
                                <p className="text-xs text-muted-foreground">Assigned</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                <Card className="glass-card">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-emerald-500/10">
                                <CheckCircle2 className="h-5 w-5 text-emerald-400" />
                            </div>
                            <div>
                                <p className="text-2xl font-bold">{stats.done}</p>
                                <p className="text-xs text-muted-foreground">Done</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                <Card className="glass-card">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-red-500/10">
                                <AlertCircle className="h-5 w-5 text-red-400" />
                            </div>
                            <div>
                                <p className="text-2xl font-bold">{stats.missing}</p>
                                <p className="text-xs text-muted-foreground">Missing</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Pending Invitations */}
            <PendingInvitations />

            {/* Filter */}
            <div className="flex gap-2 flex-wrap">
                {['all', 'assigned', 'missing', 'done'].map((f) => (
                    <Button
                        key={f}
                        variant={filter === f ? 'default' : 'outline'}
                        size="sm"
                        onClick={() => setFilter(f)}
                        className={filter === f ? 'gradient-primary text-white' : ''}
                    >
                        {f === 'all' ? 'All' : statusConfig[f as keyof typeof statusConfig]?.label || f}
                    </Button>
                ))}
            </div>

            {/* Assignment List */}
            {filteredAssignments.length === 0 ? (
                <Card className="glass-card">
                    <CardContent className="py-12 text-center">
                        <ClipboardList className="h-12 w-12 mx-auto mb-4 text-muted-foreground/50" />
                        <p className="text-muted-foreground">No assignments found</p>
                    </CardContent>
                </Card>
            ) : (
                <div className="space-y-3">
                    {filteredAssignments.map((assignment) => (
                        <AssignmentCard
                            key={assignment.id}
                            assignment={assignment}
                            onStatusChange={(status) => updateStatus(assignment.id, status)}
                            onDelete={() => deleteAssignment(assignment.id)}
                        />
                    ))}
                </div>
            )}

            {/* Google Reconnect Alert Dialog */}
            <AlertDialog open={googleAlert.open} onOpenChange={(open) => setGoogleAlert((prev) => ({ ...prev, open }))}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle className="flex items-center gap-2">
                            <AlertCircle className="h-5 w-5 text-amber-500" />
                            Google Account Not Connected
                        </AlertDialogTitle>
                        <AlertDialogDescription className="space-y-2">
                            <span className="block">
                                {googleAlert.message || 'Your Google account needs to be connected to import assignments from Google Classroom.'}
                            </span>
                            <span className="block text-xs text-muted-foreground">
                                Click &quot;Reconnect Now&quot; to re-authorize your Google account, or go to Settings to manage your accounts.
                            </span>
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <Button variant="outline" onClick={() => setGoogleAlert({ open: false, message: '' })}>
                            Maybe Later
                        </Button>
                        <Button
                            onClick={async () => {
                                setGoogleAlert({ open: false, message: '' })
                                try {
                                    const res = await fetch('/api/auth/google')
                                    const { authUrl } = await res.json()
                                    window.location.href = authUrl
                                } catch {
                                    window.location.href = '/dashboard/settings'
                                }
                            }}
                            className="gap-2"
                        >
                            <GoogleIcon className="h-4 w-4" />
                            Reconnect Now
                        </Button>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </div>
    )
}

function AssignmentCard({
    assignment,
    onStatusChange,
    onDelete
}: {
    assignment: Assignment
    onStatusChange: (status: Assignment['status']) => void
    onDelete: () => void
}) {
    const config = statusConfig[assignment.status]
    const StatusIcon = config.icon
    const isMissing = assignment.status === 'missing'
    const isDueToday = assignment.due_date && isToday(new Date(assignment.due_date))

    return (
        <Card className={cn(
            "glass-card group transition-all duration-300",
            isMissing && "border-red-500/50"
        )}>
            <CardContent className="py-4">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                    <div className="flex items-center gap-4 flex-1 min-w-0 w-full">
                        {/* Status Badge */}
                        <div className={cn("p-2 rounded-lg shrink-0", config.color.split(' ')[0])}>
                            <StatusIcon className={cn("h-5 w-5", config.color.split(' ')[1])} />
                        </div>

                        {/* Info */}
                        <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2">
                                <h3 className="font-medium truncate">{assignment.title}</h3>
                                {assignment.is_group && (
                                    <span className="flex items-center gap-1 text-xs bg-violet-500/10 text-violet-400 px-2 py-0.5 rounded-full shrink-0">
                                        <Users className="h-3 w-3" />
                                        Group
                                    </span>
                                )}
                            </div>
                            <div className="flex items-center gap-3 text-sm text-muted-foreground mt-1">
                                {assignment.course && <span>{assignment.course}</span>}
                                {assignment.due_date && (
                                    <span className={cn(
                                        "flex items-center gap-1",
                                        isMissing && "text-red-400",
                                        isDueToday && !isMissing && "text-yellow-400"
                                    )}>
                                        <Calendar className="h-3 w-3" />
                                        {isMissing ? 'Missing: ' : isDueToday ? 'Today: ' : ''}
                                        {format(new Date(assignment.due_date), 'MMM d, h:mm a')}
                                    </span>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* Actions */}
                    <div className="flex items-center gap-2 shrink-0 sm:self-auto self-end w-full sm:w-auto justify-end">
                        {/* Group Actions */}
                        {assignment.is_group && assignment.group_id ? (
                            <Sheet>
                                <SheetTrigger asChild>
                                    <Button variant="outline" size="sm" className="gap-1">
                                        <MessageCircle className="h-3.5 w-3.5" />
                                        <span className="hidden sm:inline">Chat</span>
                                    </Button>
                                </SheetTrigger>
                                <SheetContent side="right" className="w-87.5 sm:w-100 p-0">
                                    <GroupChat groupId={assignment.group_id} assignmentTitle={assignment.title} />
                                </SheetContent>
                            </Sheet>
                        ) : (
                            <Button
                                variant="outline"
                                size="sm"
                                className="gap-1"
                                onClick={() => toast.info('Group invites coming soon!')}
                            >
                                <UserPlus className="h-3.5 w-3.5" />
                                <span className="hidden sm:inline">Invite</span>
                            </Button>
                        )}

                        <Select value={assignment.status} onValueChange={(v) => onStatusChange(v as Assignment['status'])}>
                            <SelectTrigger className="w-32.5">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="assigned">Assigned</SelectItem>
                                <SelectItem value="missing">Missing</SelectItem>
                                <SelectItem value="done">Done</SelectItem>
                            </SelectContent>
                        </Select>
                        <Button
                            variant="ghost"
                            size="icon"
                            className="h-8 w-8 opacity-0 group-hover:opacity-100 text-muted-foreground hover:text-destructive"
                            onClick={onDelete}
                        >
                            <Trash2 className="h-4 w-4" />
                        </Button>
                    </div>
                </div>
            </CardContent>
        </Card>
    )
}

'use client'

import { useCallback, useEffect, useMemo, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select'
import {
    Calendar,
    CheckCircle2,
    XCircle,
    MinusCircle,
    Loader2,
    TrendingUp,
    AlertTriangle,
    Calculator,
    ChevronLeft,
    ChevronRight,
    RotateCcw,
    GraduationCap,
    Palmtree,
    Settings
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { toast } from 'sonner'
import { format, startOfWeek, addDays, isSameDay, parseISO, isWithinInterval } from 'date-fns'
import type { Semester, SemesterBreak } from '@/types'
import Link from 'next/link'

interface ClassSchedule {
    id: string
    name: string
    short_name: string | null
    day_of_week: number
    start_time: string
    end_time: string
    color: string
    semester_id: string | null
}

interface AttendanceRecord {
    id: string
    class_schedule_id: string | null
    date: string
    status: 'present' | 'absent' | 'cancelled'
    semester_id: string | null
}

export default function AttendancePage() {
    const [classes, setClasses] = useState<ClassSchedule[]>([])
    const [records, setRecords] = useState<AttendanceRecord[]>([])
    const [semesters, setSemesters] = useState<Semester[]>([])
    const [breaks, setBreaks] = useState<SemesterBreak[]>([])
    const [loading, setLoading] = useState(true)
    const [loadError, setLoadError] = useState<string | null>(null)
    const [selectedClass, setSelectedClass] = useState<string>('all')
    const [selectedSemester, setSelectedSemester] = useState<string>('all')
    const [targetPercentage, setTargetPercentage] = useState<number>(75)
    const [weekOffset, setWeekOffset] = useState(0)
    const supabase = useMemo(() => createClient(), [])

    const today = useMemo(() => new Date(), [])

    const weekStart = useMemo(() => {
        const today = new Date()
        return addDays(startOfWeek(today, { weekStartsOn: 1 }), weekOffset * 7)
    }, [weekOffset])

    const weekDays = useMemo(() => {
        return Array.from({ length: 7 }, (_, i) => addDays(weekStart, i))
    }, [weekStart])

    const formatSupabaseError = (error: unknown) => {
        if (!error || typeof error !== 'object') return 'Unknown error'

        const anyErr = error as { message?: string; details?: string; hint?: string; code?: string }
        const parts = [anyErr.message, anyErr.details, anyErr.hint].filter(Boolean)

        const msg = parts.join(' · ')
        if (msg) return msg

        return anyErr.code ? `Error code: ${anyErr.code}` : 'Unknown error'
    }

    const fetchData = useCallback(async () => {
        try {
            setLoadError(null)
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) {
                setLoadError('Not signed in')
                return
            }

            // Fetch all data in parallel
            const [classRes, attendanceRes, semesterRes, breaksRes] = await Promise.all([
                supabase
                    .from('class_schedules')
                    .select('id, name, short_name, day_of_week, start_time, end_time, color, semester_id')
                    .eq('user_id', user.id),
                supabase
                    .from('attendance_records')
                    .select('id, class_schedule_id, date, status, semester_id')
                    .eq('user_id', user.id),
                supabase
                    .from('semesters')
                    .select('*')
                    .eq('user_id', user.id)
                    .order('start_date', { ascending: false }),
                supabase
                    .from('semester_breaks')
                    .select('*')
                    .eq('user_id', user.id)
            ])

            if (classRes.error) throw classRes.error
            if (attendanceRes.error) throw attendanceRes.error

            const sortedClasses = (classRes.data || []).slice().sort((a, b) => {
                if (a.day_of_week !== b.day_of_week) return a.day_of_week - b.day_of_week
                return String(a.start_time).localeCompare(String(b.start_time))
            })

            setClasses(sortedClasses)
            setRecords(attendanceRes.data || [])
            setSemesters(semesterRes.data || [])
            setBreaks(breaksRes.data || [])

            // Auto-select active semester
            const activeSem = (semesterRes.data || []).find(s => s.is_active)
            if (activeSem) {
                setSelectedSemester(activeSem.id)
            }
        } catch (error) {
            console.error('Error fetching data:', error)
            const msg = formatSupabaseError(error)
            setLoadError(msg)
            toast.error(`Failed to load attendance: ${msg}`)
        } finally {
            setLoading(false)
        }
    }, [supabase])

    useEffect(() => {
        fetchData()
    }, [fetchData])

    // Filter classes by selected semester
    const filteredClasses = useMemo(() => {
        if (selectedSemester === 'all') return classes
        return classes.filter(c => c.semester_id === selectedSemester || c.semester_id === null)
    }, [classes, selectedSemester])

    // Filter records by selected semester
    const filteredRecords = useMemo(() => {
        if (selectedSemester === 'all') return records
        return records.filter(r => r.semester_id === selectedSemester || r.semester_id === null)
    }, [records, selectedSemester])

    // Get breaks for selected semester
    const semesterBreaks = useMemo(() => {
        if (selectedSemester === 'all') return breaks
        return breaks.filter(b => b.semester_id === selectedSemester)
    }, [breaks, selectedSemester])

    // Check if a date falls within a break
    const getBreakForDate = (date: Date): SemesterBreak | null => {
        return semesterBreaks.find(brk => {
            return isWithinInterval(date, {
                start: parseISO(brk.start_date),
                end: parseISO(brk.end_date)
            })
        }) || null
    }

    const markAttendance = async (classId: string, date: Date, status: 'present' | 'absent' | 'cancelled') => {
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) return

            const dateStr = format(date, 'yyyy-MM-dd')

            // Check if record exists
            const existing = records.find((r) => r.class_schedule_id === classId && r.date === dateStr)

            if (existing) {
                // Update existing record
                const { error } = await supabase
                    .from('attendance_records')
                    .update({ status })
                    .eq('id', existing.id)

                if (error) throw error

                setRecords((prev) =>
                    prev.map((r) => (r.id === existing.id ? { ...r, status } : r))
                )
            } else {
                // Create new record with semester_id
                const { data: inserted, error } = await supabase
                    .from('attendance_records')
                    .insert({
                        user_id: user.id,
                        class_schedule_id: classId,
                        date: dateStr,
                        status,
                        semester_id: selectedSemester !== 'all' ? selectedSemester : null
                    })
                    .select('id, class_schedule_id, date, status, semester_id')
                    .single()

                if (error) throw error

                if (inserted) {
                    setRecords((prev) => [inserted as AttendanceRecord, ...prev])
                }
            }

            fetchData()
        } catch (error) {
            console.error('Error marking attendance:', error)
            const msg = formatSupabaseError(error)
            toast.error(`Failed to update attendance: ${msg}`)
        }
    }

    const getAttendanceForDay = (classId: string, date: Date): AttendanceRecord | undefined => {
        const dateStr = format(date, 'yyyy-MM-dd')
        return records.find(
            r => r.class_schedule_id === classId && r.date === dateStr
        )
    }

    const calculateStats = (classId?: string) => {
        const relevantRecords = classId && classId !== 'all'
            ? filteredRecords.filter(r => r.class_schedule_id === classId)
            : filteredRecords

        const total = relevantRecords.filter(r => r.status !== 'cancelled').length
        const present = relevantRecords.filter(r => r.status === 'present').length
        const absent = relevantRecords.filter(r => r.status === 'absent').length
        const percentage = total > 0 ? Math.round((present / total) * 100) : 0

        return { total, present, absent, percentage }
    }

    // Calculate stats by subject NAME (aggregates all class slots with same name)
    const calculateStatsBySubjectName = (subjectName: string) => {
        // Get all class IDs that share this subject name
        const classIdsForSubject = filteredClasses
            .filter(c => c.name === subjectName)
            .map(c => c.id)

        // Get all records for these class IDs
        const relevantRecords = filteredRecords.filter(r =>
            r.class_schedule_id && classIdsForSubject.includes(r.class_schedule_id)
        )

        const total = relevantRecords.filter(r => r.status !== 'cancelled').length
        const present = relevantRecords.filter(r => r.status === 'present').length
        const absent = relevantRecords.filter(r => r.status === 'absent').length
        const percentage = total > 0 ? Math.round((present / total) * 100) : 0

        return { total, present, absent, percentage }
    }

    const calculateBunkable = (classId: string) => {
        const stats = calculateStats(classId)
        if (stats.percentage <= targetPercentage) return 0

        const maxBunkable = Math.floor(
            (stats.present - (targetPercentage * stats.total) / 100) / (1 + targetPercentage / 100)
        )

        return Math.max(0, maxBunkable)
    }

    // Calculate bunkable by subject name
    const calculateBunkableBySubjectName = (subjectName: string) => {
        const stats = calculateStatsBySubjectName(subjectName)
        if (stats.percentage <= targetPercentage) return 0

        const maxBunkable = Math.floor(
            (stats.present - (targetPercentage * stats.total) / 100) / (1 + targetPercentage / 100)
        )

        return Math.max(0, maxBunkable)
    }

    // Calculate overall stats - use name-based aggregation when a class is selected
    const overallStats = useMemo(() => {
        if (selectedClass === 'all') {
            return calculateStats('all')
        }
        // Find the subject name for the selected class
        const selectedCls = filteredClasses.find(c => c.id === selectedClass)
        if (selectedCls) {
            return calculateStatsBySubjectName(selectedCls.name)
        }
        return calculateStats(selectedClass)
    }, [selectedClass, filteredClasses, filteredRecords])

    const visibleWeekDays = useMemo(() => {
        if (selectedClass === 'all') return weekDays

        const cls = filteredClasses.find((c) => c.id === selectedClass)
        if (!cls) return weekDays

        const match = weekDays.find((d) => d.getDay() === cls.day_of_week)
        return match ? [match] : weekDays
    }, [filteredClasses, selectedClass, weekDays])

    const selectedSemesterName = semesters.find(s => s.id === selectedSemester)?.name

    if (loading) {
        return (
            <div className="flex items-center justify-center h-[50vh]">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    return (
        <div className="space-y-8">
            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold gradient-text">Attendance Tracker</h1>
                    <p className="text-muted-foreground mt-1">Track and analyze your class attendance</p>
                </div>
                <div className="flex flex-wrap items-center gap-2">
                    {/* Semester Selector */}
                    <div className="flex items-center gap-2">
                        <GraduationCap className="h-4 w-4 text-muted-foreground" />
                        <Select value={selectedSemester} onValueChange={(v) => {
                            setSelectedSemester(v)
                            setSelectedClass('all') // Reset class filter when semester changes
                        }}>
                            <SelectTrigger className="w-40">
                                <SelectValue placeholder="All Semesters" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">All Semesters</SelectItem>
                                {semesters.map((sem) => (
                                    <SelectItem key={sem.id} value={sem.id}>
                                        {sem.name} {sem.is_active && '✓'}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                        <Link href="/dashboard/settings/semesters">
                            <Button variant="ghost" size="icon" className="h-9 w-9">
                                <Settings className="h-4 w-4" />
                            </Button>
                        </Link>
                    </div>

                    {/* Class Selector */}
                    <Select value={selectedClass} onValueChange={setSelectedClass}>
                        <SelectTrigger className="w-50">
                            <SelectValue placeholder="All Classes" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">All Classes</SelectItem>
                            {filteredClasses.map((cls) => (
                                <SelectItem key={cls.id} value={cls.id}>
                                    {cls.short_name || cls.name}
                                </SelectItem>
                            ))}
                        </SelectContent>
                    </Select>

                    {/* Target Percentage Selector */}
                    <Select value={targetPercentage.toString()} onValueChange={(v) => setTargetPercentage(parseInt(v))}>
                        <SelectTrigger className="w-28">
                            <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="75">75% target</SelectItem>
                            <SelectItem value="80">80% target</SelectItem>
                            <SelectItem value="85">85% target</SelectItem>
                            <SelectItem value="90">90% target</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </div>

            {/* Semester indicator */}
            {selectedSemester !== 'all' && selectedSemesterName && (
                <div className="flex items-center gap-2 text-sm text-muted-foreground bg-purple-500/10 px-3 py-2 rounded-lg w-fit">
                    <GraduationCap className="h-4 w-4 text-purple-400" />
                    <span>Viewing: <span className="text-purple-400 font-medium">{selectedSemesterName}</span></span>
                    {semesterBreaks.length > 0 && (
                        <span className="text-muted-foreground">• {semesterBreaks.length} break{semesterBreaks.length > 1 && 's'} configured</span>
                    )}
                </div>
            )}

            {/* Subject-wise Attendance Breakdown */}
            {filteredClasses.length > 0 && (
                <div className="space-y-4">
                    <div className="flex items-center justify-between">
                        <h2 className="text-lg font-semibold">Subject-wise Attendance</h2>
                        <p className="text-sm text-muted-foreground">
                            Click a subject to view its weekly log
                        </p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                        {/* Get unique classes (by name) to avoid duplicates for different days */}
                        {Array.from(new Map(filteredClasses.map(c => [c.name, c])).values()).map((cls) => {
                            // Use name-based stats to aggregate across all class slots
                            const stats = calculateStatsBySubjectName(cls.name)
                            const bunkable = calculateBunkableBySubjectName(cls.name)
                            const isSelected = selectedClass === cls.id
                            const isAtRisk = stats.percentage < targetPercentage && stats.total > 0

                            return (
                                <Card
                                    key={cls.id}
                                    onClick={() => setSelectedClass(isSelected ? 'all' : cls.id)}
                                    className={cn(
                                        "glass-card cursor-pointer transition-all hover:scale-[1.02]",
                                        isSelected && "ring-2 ring-primary",
                                        isAtRisk && "border-red-500/30"
