                                                            <AlertDialogFooter>
                                                                <AlertDialogCancel className="border-border">Cancel</AlertDialogCancel>
                                                                <AlertDialogAction
                                                                    onClick={() => removeCourse(course.id)}
                                                                    className="bg-red-500 hover:bg-red-600 text-white"
                                                                >
                                                                    Delete
                                                                </AlertDialogAction>
                                                            </AlertDialogFooter>
                                                        </AlertDialogContent>
                                                    </AlertDialog>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </CollapsibleContent>
                        </Collapsible>
                    )
                })}
            </div>

            {/* GPA Scale Reference */}
            <Card className="glass-card border-white/6">
