    red: 'text-red-400 bg-red-500/10 border-red-500/30',
}

import NProgress from 'nprogress'
import { ClientOnly } from '../ClientOnly'

function NavItem({
    href,
    label,
    icon: Icon,
    color,
    isActive,
    collapsed,
    onClick
}: {
    href: string
    label: string
    icon: React.ComponentType<{ className?: string }>
    color: string
    isActive: boolean
    collapsed: boolean
    onClick?: () => void
}) {
    const handleClick = () => {
        if (!isActive) {
            NProgress.start()
        }
        onClick?.()
    }

    const [mounted, setMounted] = useState(false)
    useEffect(() => {
        // eslint-disable-next-line
        setMounted(true)
    }, [])

    return (
        <Link
            href={href}
            onClick={handleClick}
            prefetch={true}
            scroll={false}
        >
            <div
                className={cn(
                    "group flex items-center gap-3 px-3 py-2 rounded-lg transition-all duration-200 border border-transparent",
                    "hover:bg-white/5 hover:border-white/5",
                    isActive
                        ? activeColors[color]
                        : "text-muted-foreground"
                )}
            >
                <div className="flex items-center justify-center">
                    {/* Hydration fix: Only render icon after mount to ensure match with server (which renders placeholder) */}
                    {mounted ? (
                        <Icon className={cn(
                            "h-4 w-4 aspect-square shrink-0 transition-colors",
                            isActive ? '' : iconColors[color]
                        )} />
                    ) : (
                        <div className="h-4 w-4 aspect-square" />
                    )}
                </div>
                {!collapsed && (
                    <span
                        suppressHydrationWarning
                        className={cn(
                            "text-sm font-medium transition-colors",
                            isActive ? '' : 'group-hover:text-foreground'
                        )}
                    >
                        {label}
                    </span>
                )}
            </div>
        </Link>
    )
}

export function Sidebar({ user }: SidebarProps) {
    const [collapsed, setCollapsed] = useState(false)
    const pathname = usePathname()
    const router = useRouter()
    const supabase = createClient()
    const { isAdmin } = useAuth()
    const { isEnabled: isFeatureEnabled } = useFeatureFlags()

    const handleLogout = async () => {
        await supabase.auth.signOut()
        router.push('/login')
        router.refresh()
    }

    // Filter nav items by feature flags (admins bypass)
    const filterByFlags = (items: NavItem[]) =>
        items.filter(item => {
            if (!item.featureFlag) return true
            if (isAdmin) return true
            return isFeatureEnabled(item.featureFlag)
        })

    // Build nav groups, conditionally including admin
    const allNavGroups = [
        ...navGroups.map(g => ({ ...g, items: filterByFlags(g.items) })).filter(g => g.items.length > 0),
        ...(isAdmin ? [{
            title: 'Admin' as string | null,
            items: [
                { href: '/dashboard/admin', label: 'Admin Panel', icon: Shield, color: 'red' } as NavItem,
            ]
        }] : [])
    ]

    const userInitials = user?.user_metadata?.full_name
        ?.split(' ')
        .map((n: string) => n[0])
        .join('')
        .toUpperCase() || user?.email?.[0].toUpperCase() || 'G'

    return (
        <aside
            className={cn(
                "h-screen flex flex-col bg-sidebar backdrop-blur-2xl border-r border-sidebar-border transition-all duration-300",
                collapsed ? "w-18" : "w-64"
            )}
        >
            {/* Toggle Button - Absolute Positioned */}
            <Button
                variant="ghost"
                size="icon"
                onClick={() => setCollapsed(!collapsed)}
                className={cn(
                    "absolute -right-3 top-6 z-50 h-6 w-6 rounded-full border bg-card shadow-md transition-all duration-300 hover:bg-accent",
                    "border-border text-muted-foreground hover:text-foreground"
                )}
            >
                {collapsed ? <ChevronRight className="h-3 w-3" /> : <ChevronLeft className="h-3 w-3" />}
            </Button>

            {/* Header */}
            <div className={cn(
                "flex items-center p-4 border-b border-sidebar-border h-16.25",
                collapsed ? "justify-center" : "justify-between"
            )}>
                <Link href="/dashboard" className="flex items-center gap-2 overflow-hidden hover:opacity-80 transition-opacity">
                    <div className="w-8 h-8 rounded-lg gradient-primary flex items-center justify-center shrink-0">
                        <GraduationCap className="h-4 w-4 text-black" />
                    </div>
                    {!collapsed && (
                        <h1 className="text-xl font-bold gradient-text whitespace-nowrap opacity-100 transition-opacity duration-300">
                            StudentHub
                        </h1>
                    )}
                </Link>
            </div>

            {/* Navigation */}
            <nav className="flex-1 px-3 py-4 space-y-6 overflow-y-auto scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent">
                {allNavGroups.map((group, i) => (
                    <div key={i} className="space-y-1">
                        {!collapsed && group.title && (
                            <h4 className="px-3 text-xs font-semibold text-muted-foreground/50 uppercase tracking-wider mb-2">
                                {group.title}
                            </h4>
                        )}
                        {collapsed && group.title && i > 0 && (
                            <div className="h-px bg-white/5 my-2 mx-2" />
                        )}
                        {group.items.map((item) => (
                            <NavItem
                                key={item.href}
                                href={item.href}
                                label={item.label}
                                icon={item.icon}
                                color={item.color}
                                isActive={pathname === item.href || (item.href !== '/dashboard' && pathname.startsWith(item.href))}
                                collapsed={collapsed}
                            />
                        ))}
                    </div>
                ))}
            </nav>

            {/* User Menu */}
            <div className="p-3 border-t border-sidebar-border">
                {user ? (
                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button
                                variant="ghost"
                                className={cn(
                                    "w-full justify-start gap-3 px-3 py-6 hover:bg-white/6 rounded-xl transition-all",
                                    collapsed && "justify-center px-0"
                                )}
                            >
                                <Avatar className="h-9 w-9 ring-2 ring-violet-500/20">
                                    <AvatarImage src={user.user_metadata?.avatar_url} />
                                    <AvatarFallback className="bg-linear-to-br from-violet-500 to-fuchsia-500 text-black font-medium">
                                        {userInitials}
                                    </AvatarFallback>
                                </Avatar>
                                {!collapsed && (
                                    <div className="flex flex-col items-start text-left overflow-hidden">
                                        <span className="text-sm font-medium text-foreground truncate w-full">
                                            {user.user_metadata?.full_name || 'User'}
                                        </span>
                                        <span className="text-xs text-muted-foreground truncate w-full">
                                            {user.email}
                                        </span>
                                    </div>
                                )}
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end" className="w-56 bg-popover backdrop-blur-xl border-border">
                            <DropdownMenuLabel className="text-muted-foreground">My Account</DropdownMenuLabel>
                            <DropdownMenuSeparator className="bg-border" />
                            <DropdownMenuItem
                                onClick={() => router.push('/dashboard/settings')}
                                className="text-foreground focus:bg-accent cursor-pointer"
                            >
                                <Settings className="mr-2 h-4 w-4" />
                                Settings
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={handleLogout} className="text-rose-500 focus:bg-rose-500/10 focus:text-rose-500 cursor-pointer">
                                <LogOut className="mr-2 h-4 w-4" />
                                Logout
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                    </DropdownMenu>
                ) : (
                    <Link href="/login">
                        <Button
                            className={cn(
                                "w-full justify-start gap-3 px-3 py-6 bg-linear-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 text-white rounded-xl transition-all",
                                collapsed && "justify-center px-0"
                            )}
                        >
                            <LogOut className="h-5 w-5 rotate-180" />
                            {!collapsed && <span>Sign In</span>}
                        </Button>
                    </Link>
                )}
            </div>
        </aside>
    )
}

