'use client'

import { useState, useEffect, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'

interface FeatureFlags {
    [key: string]: boolean
}

/**
 * Hook to fetch feature flags from the database.
 * Returns { isEnabled, isLoading, flags }
 * - Admins bypass flags (everything is enabled)
 * - Caches flags for the session
 */
export function useFeatureFlags() {
    const [flags, setFlags] = useState<FeatureFlags>({})
    const [isLoading, setIsLoading] = useState(true)

    useEffect(() => {
        // Check sessionStorage cache first
        try {
            const cached = sessionStorage.getItem('feature-flags')
            if (cached) {
                setFlags(JSON.parse(cached))
                setIsLoading(false)
                return
            }
        } catch { }

        const supabase = createClient()
        supabase
            .from('feature_flags')
            .select('name, is_enabled')
            .then(({ data }) => {
                if (data) {
                    const flagMap: FeatureFlags = {}
                    for (const flag of data) {
                        flagMap[flag.name] = flag.is_enabled
                    }
                    setFlags(flagMap)
                    try { sessionStorage.setItem('feature-flags', JSON.stringify(flagMap)) } catch { }
                }
                setIsLoading(false)
            })
    }, [])

    const isEnabled = useCallback((name: string): boolean => {
        // If flag doesn't exist, default to enabled
        if (!(name in flags)) return true
        return flags[name]
    }, [flags])

    return { isEnabled, isLoading, flags }
}

'use client'

import { useEffect, useRef, useCallback, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { toast } from 'sonner'

interface SyncResult {
    tasks?: { synced: number }
    classroom?: { imported: number }
    calendar?: { synced: number }
}

// Background sync hook - runs sync on mount and periodically
export function useGoogleSync(options?: {
    interval?: number  // Sync interval in minutes (default: 10)
    enabled?: boolean
    showToasts?: boolean
    skipClassroom?: boolean
}) {
    const { interval = 10, enabled = true, showToasts = false } = options || {}
    const syncInProgress = useRef(false)
    const lastSync = useRef<Date | null>(null)
    const hasGoogleAccount = useRef<boolean | null>(null)
    const [needsReconnect, setNeedsReconnect] = useState(false)
    const [reconnectMessage, setReconnectMessage] = useState('')
    const reconnectDismissed = useRef(
        typeof window !== 'undefined' && sessionStorage.getItem('google-reconnect-dismissed') === 'true'
    )

    const dismissReconnect = useCallback(() => {
        setNeedsReconnect(false)
        setReconnectMessage('')
        reconnectDismissed.current = true
        try { sessionStorage.setItem('google-reconnect-dismissed', 'true') } catch { }
    }, [])

    const syncAll = useCallback(async (): Promise<SyncResult> => {
        if (syncInProgress.current) return {}
        syncInProgress.current = true

        const results: SyncResult = {}

        try {
            // Check if user has any Google account connected (cached after first check)
            if (hasGoogleAccount.current === null) {
                try {
                    const supabase = createClient()
                    const { data: { user } } = await supabase.auth.getUser()
                    if (!user) { hasGoogleAccount.current = false; return results }
                    const { count } = await supabase
                        .from('google_accounts')
                        .select('id', { count: 'exact', head: true })
                        .eq('user_id', user.id)
                    hasGoogleAccount.current = (count ?? 0) > 0
                } catch {
                    hasGoogleAccount.current = false
                }
            }

            // Skip all sync requests if no Google account is connected
            if (!hasGoogleAccount.current) return results

            // Skip sync if user dismissed the reconnect dialog this session
            if (reconnectDismissed.current) return results

            // 1. Sync Google Tasks (fetch new tasks from Google)
            try {
                const tasksRes = await fetch('/api/google/sync', { method: 'POST' })
                if (tasksRes.ok) {
                    const data = await tasksRes.json()
                    results.tasks = { synced: data.synced || 0 }
                } else if (tasksRes.status === 401 || tasksRes.status === 403) {
                    // Token expired/revoked — check if reconnect is needed
                    try {
                        const data = await tasksRes.json()
                        if (data.needsReconnect && !reconnectDismissed.current) {
                            setNeedsReconnect(true)
                            setReconnectMessage(data.error || 'Your Google session has expired. Please reconnect your Google account.')
                        }
                    } catch {
                        // Couldn't parse JSON, still mark as needing reconnect
                    }
                    hasGoogleAccount.current = false
                    return results
                }
            } catch {
                // Network error - silently ignore
            }

            // 2. Import Google Classroom assignments (skip if feature is disabled)
            if (!options?.skipClassroom) {
                try {
                    const classroomRes = await fetch('/api/google/classroom', { method: 'POST' })
                    if (classroomRes.ok) {
                        const data = await classroomRes.json()
                        results.classroom = { imported: data.imported || 0 }
                    } else if (classroomRes.status === 401 || classroomRes.status === 403) {
                        // Token expired/revoked — surface reconnect dialog
                        try {
                            const data = await classroomRes.json()
                            if (data.needsReconnect && !reconnectDismissed.current) {
                                setNeedsReconnect(true)
                                setReconnectMessage(data.error || 'Your Google session has expired. Please reconnect your Google account.')
                            }
                        } catch {
                            // Couldn't parse JSON
                        }
                        hasGoogleAccount.current = false
                        return results
                    }
                } catch {
                    // Network error - silently ignore
                }
            }

            // Note: Calendar sync would go here when implemented

            lastSync.current = new Date()

            // Show toast if anything was synced
            if (showToasts) {
                const totalSynced = (results.tasks?.synced || 0) + (results.classroom?.imported || 0)
                if (totalSynced > 0) {
                    toast.success(`Synced ${totalSynced} items from Google`)
                }
            }

            return results
        } finally {
            syncInProgress.current = false
        }
    }, [showToasts])

    useEffect(() => {
        if (!enabled) return

        // Initial sync on mount (with delay to not block initial render)
        const initialTimeout = setTimeout(() => {
            syncAll()
        }, 2000)

        // Periodic sync
        const intervalMs = interval * 60 * 1000
        const syncInterval = setInterval(() => {
            syncAll()
        }, intervalMs)

        return () => {
            clearTimeout(initialTimeout)
            clearInterval(syncInterval)
        }
    }, [enabled, interval, syncAll])

    return {
        syncAll,
        lastSync: lastSync.current,
        syncInProgress: syncInProgress.current,
        needsReconnect,
        reconnectMessage,
        dismissReconnect,
    }
}

type Task<T> = {
    fn: () => Promise<T>
    resolve: (value: T | PromiseLike<T>) => void
    reject: (reason?: any) => void
    queuedAt: number
    timeoutId?: NodeJS.Timeout
}

export interface AILimiterOptions {
    concurrency: number
    maxQueue: number
    timeoutMs: number
    failureThreshold: number
    cooldownMs: number
}

export class AILimiter {
    private concurrency: number
    private maxQueue: number
    private timeoutMs: number
    private failureThreshold: number
    private cooldownMs: number

    private active = 0
    private queue: Task<any>[] = []
    private failures = 0
    private openUntil: number | null = null

    constructor(opts: AILimiterOptions) {
        this.concurrency = opts.concurrency
        this.maxQueue = opts.maxQueue
        this.timeoutMs = opts.timeoutMs
        this.failureThreshold = opts.failureThreshold
        this.cooldownMs = opts.cooldownMs
    }

    isOpen() {
        if (this.openUntil && Date.now() < this.openUntil) return true
        if (this.openUntil && Date.now() >= this.openUntil) {
            // reset circuit
            this.openUntil = null
            this.failures = 0
            return false
        }
        return false
    }

    async run<T>(fn: () => Promise<T>): Promise<T> {
        if (this.isOpen()) {
            return Promise.reject(new Error('AI service temporarily unavailable (circuit open)'))
        }

        if (this.active < this.concurrency) {
            return this.execute(fn)
        }

        if (this.queue.length >= this.maxQueue) {
            return Promise.reject(new Error('AI service busy — try again later'))
        }

        // Enqueue
        return new Promise<T>((resolve, reject) => {
            const task: Task<T> = { fn, resolve, reject, queuedAt: Date.now() }
            // Set a timeout for waiting in queue — if not started within timeout, reject
            task.timeoutId = setTimeout(() => {
                // Remove from queue if still present
                const idx = this.queue.indexOf(task as any)
                if (idx !== -1) this.queue.splice(idx, 1)
                reject(new Error('AI request timed out in queue'))
            }, this.timeoutMs)
            this.queue.push(task as any)
        })
    }

    private async execute<T>(fn: () => Promise<T>): Promise<T> {
        this.active++
        let finished = false

        try {
            const result = await this.runWithTimeout(fn)
            finished = true
            this.onSuccess()
            return result
        } catch (err) {
            this.onFailure()
            throw err
        } finally {
            this.active--
            // Start queued tasks if any
            this.processQueue()
        }
    }

    private runWithTimeout<T>(fn: () => Promise<T>): Promise<T> {
        return new Promise<T>((resolve, reject) => {
            let finished = false
            const timer = setTimeout(() => {
                if (!finished) {
                    finished = true
                    reject(new Error('AI request timed out'))
                }
            }, this.timeoutMs)

            fn()
                .then((res) => {
                    if (finished) return
                    finished = true
                    clearTimeout(timer)
                    resolve(res)
                })
                .catch((err) => {
                    if (finished) return
                    finished = true
                    clearTimeout(timer)
                    reject(err)
                })
        })
    }

    private processQueue() {
        while (this.active < this.concurrency && this.queue.length > 0) {
            const task = this.queue.shift()!
            if (task.timeoutId) clearTimeout(task.timeoutId)

            // Execute and resolve/reject accordingly
            this.execute(task.fn)
                .then((v) => task.resolve(v))
                .catch((e) => task.reject(e))
        }
    }

    private onSuccess() {
        this.failures = 0
    }

    private onFailure() {
        this.failures++
        if (this.failures >= this.failureThreshold) {
            this.openUntil = Date.now() + this.cooldownMs
            console.warn(`AI circuit opened for ${this.cooldownMs}ms after ${this.failures} failures`)
        }
    }
}

// Default instance — per-process limiter
export const aiLimiter = new AILimiter({
    concurrency: 5, // per-user preference: 3-5; choose 5 conservative upper bound
    maxQueue: 20,
    timeoutMs: 15000, // 15s
    failureThreshold: 5,
    cooldownMs: 60000, // 60s cooldown
})

import { NextResponse } from 'next/server'
import { z, ZodSchema } from 'zod'
import { getAuthenticatedUser, unauthorizedResponse } from '@/lib/api-utils'
import { createApiErrorResponse } from '@/lib/errors'
import { checkRateLimit, rateLimitExceededResponse, RATE_LIMITS } from '@/lib/rate-limit'
import type { User } from '@supabase/supabase-js'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface RouteHandlerContext<T = unknown> {
    /** Authenticated Supabase user (present when `auth: true`) */
    user: User
    /** Parsed & validated request body (present when `schema` is provided) */
    body: T
    /** Original request object */
    request: Request
}

interface RouteOptions<T = unknown> {
    /**
     * Zod schema to validate the JSON request body against.
     * Omit for GET / DELETE routes or routes with no body.
     */
    schema?: ZodSchema<T>

    /**
     * Whether the route requires authentication (default: `true`).
     */
    auth?: boolean

    /**
     * Rate-limit configuration.  Set to `false` to disable.
     * Defaults to 10 requests / 60 s.
     */
    rateLimit?: { maxRequests: number; windowSeconds: number; endpoint: string } | false

    /**
     * Maximum allowed `Content-Length` in bytes (default: 1 MB).
     * Prevents oversized payloads from reaching the JSON parser.
     */
    maxBodySize?: number
}

// ---------------------------------------------------------------------------
// Defaults
// ---------------------------------------------------------------------------

const DEFAULT_MAX_BODY = 1_048_576 // 1 MB
const DEFAULT_RATE_LIMIT_V2 = {
    maxRequests: RATE_LIMITS.ai_general.limit,
    windowSeconds: RATE_LIMITS.ai_general.windowSeconds,
    endpoint: RATE_LIMITS.ai_general.endpoint,
}

// ---------------------------------------------------------------------------
// Sanitiser — strips known-dangerous characters from user-supplied strings
// to reduce stored-XSS / log-injection surface area.
// ---------------------------------------------------------------------------

function deepSanitize<T>(value: T): T {
    if (typeof value === 'string') {
        // Strip NUL bytes and control chars (except whitespace)
        // eslint-disable-next-line no-control-regex
        return value.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '') as unknown as T
    }
    if (Array.isArray(value)) {
        return value.map(deepSanitize) as unknown as T
    }
    if (value !== null && typeof value === 'object') {
        const out: Record<string, unknown> = {}
        for (const [k, v] of Object.entries(value)) {
            out[k] = deepSanitize(v)
        }
        return out as T
    }
    return value
}

// ---------------------------------------------------------------------------
// Validation-error formatter – flattens Zod issues into a simple object.
// ---------------------------------------------------------------------------

function formatZodErrors(error: z.ZodError): Record<string, string> {
    const formatted: Record<string, string> = {}
    for (const issue of error.issues) {
        const path = issue.path.join('.') || '_root'
        formatted[path] = issue.message
    }
    return formatted
}

// ---------------------------------------------------------------------------
// Core wrapper
// ---------------------------------------------------------------------------

/**
 * Production-grade API route wrapper.
 *
 * Handles authentication, rate-limiting, body validation, input sanitization,
 * body-size enforcement and error handling in a single composable layer so
 * individual route handlers stay clean and focused.
 *
 * @example
 * ```ts
 * import { withValidation } from '@/lib/api-handler'
 * import { z } from 'zod'
 *
 * const schema = z.object({ text: z.string().min(1).max(2000) })
 *
 * export const POST = withValidation({ schema, rateLimit: { maxRequests: 10, windowMs: 60_000, endpoint: 'explain' } },
 *   async ({ user, body }) => {
 *     const explanation = await generateText(body.text)
 *     return NextResponse.json({ explanation })
 *   }
 * )
 * ```
 */
export function withValidation<T>(
    options: RouteOptions<T>,
    handler: (ctx: RouteHandlerContext<T>) => Promise<NextResponse>
) {
    const {
        schema,
        auth = true,
        rateLimit: rateLimitOpts = DEFAULT_RATE_LIMIT_V2,
        maxBodySize = DEFAULT_MAX_BODY,
    } = options

    return async (request: Request): Promise<NextResponse> => {
        try {
            // ---------------------------------------------------------------
            // 1. Authentication
            // ---------------------------------------------------------------
            let user: User | null = null
            if (auth) {
                user = await getAuthenticatedUser()
                if (!user) {
                    return unauthorizedResponse()
                }
            }

            // ---------------------------------------------------------------
            // 2. Rate Limiting
            // ---------------------------------------------------------------
            if (rateLimitOpts !== false && user) {
                const rl = await checkRateLimit(
                    user.id,
                    rateLimitOpts.endpoint,
                    rateLimitOpts.maxRequests,
                    rateLimitOpts.windowSeconds,
                )
                if (!rl.allowed) {
                    return rateLimitExceededResponse({
                        limit: rateLimitOpts.maxRequests,
                        remaining: rl.remaining,
                        resetAt: rl.resetAt,
                    })
                }
            }

            // ---------------------------------------------------------------
            // 3. Body size guard
            // ---------------------------------------------------------------
            const contentLength = request.headers.get('content-length')
            if (contentLength && parseInt(contentLength, 10) > maxBodySize) {
                return NextResponse.json(
                    { error: 'Request body too large' },
                    { status: 413 }
                )
            }

            // ---------------------------------------------------------------
            // 4. Parse & validate body
            // ---------------------------------------------------------------
            let body: T = undefined as unknown as T
            if (schema) {
                let rawBody: unknown
                try {
                    rawBody = await request.json()
                } catch {
                    return NextResponse.json(
                        { error: 'Invalid JSON in request body' },
                        { status: 400 }
                    )
                }

                const result = schema.safeParse(rawBody)
                if (!result.success) {
                    return NextResponse.json(
                        {
                            error: 'Validation failed',
                            details: formatZodErrors(result.error),
                        },
                        { status: 400 }
                    )
                }
                body = deepSanitize(result.data)
            }

            // ---------------------------------------------------------------
            // 5. Execute handler
            // ---------------------------------------------------------------
            return await handler({ user: user!, body, request })
        } catch (error) {
            return createApiErrorResponse(error)
        }
    }
}

